/// Contains information about the provided context. This includes the signed
/// and encrypted
/// trusted context assertion and the context provider ARN from which the
/// trusted context
/// assertion was generated.
pub const ProvidedContext = struct {
    /// The signed and encrypted trusted context assertion generated by the context
    /// provider.
    /// The trusted context assertion is signed and encrypted by Amazon Web Services
    /// STS.
    context_assertion: ?[]const u8,

    /// The context provider ARN from which the trusted context assertion was
    /// generated.
    provider_arn: ?[]const u8,
};
